class Solution:
    def minSplitMerge(self, nums1, nums2):
        from itertools import permutations
        start = tuple(nums1)
        goal = tuple(nums2)
        if start == goal:
            return 0
        n = len(nums1)
        # explore all arrangements reachable within increasing move counts
        from collections import deque
        seen = {start}
        q = deque([(start, 0)])
        while q:
            cur, d = q.popleft()
            arr = list(cur)
            for L in range(n):
                for R in range(L, n):
                    block = arr[L:R + 1]
                    rest = arr[:L] + arr[R + 1:]
                    for pos in range(len(rest) + 1):
                        nxt = tuple(rest[:pos] + block + rest[pos:])
                        if nxt == goal:
                            return d + 1
                        if nxt not in seen:
                            seen.add(nxt)
                            q.append((nxt, d + 1))
        return -1

