class Solution:
    def minSplitMerge(self, nums1, nums2):
        from collections import deque
        start = tuple(nums1)
        goal = tuple(nums2)
        n = len(nums1)
        seen = {start: 0}
        q = deque([start])
        while q:
            cur = q.popleft()
            d = seen[cur]
            if cur == goal:
                return d
            arr = list(cur)
            for L in range(n):
                for R in range(L, n):
                    rest = arr[:L] + arr[R + 1:]
                    block = arr[L:R + 1]
                    for pos in range(len(rest) + 1):
                        nxt = tuple(rest[:pos] + block + rest[pos:])
                        if nxt not in seen:
                            seen[nxt] = d + 1
                            q.append(nxt)
        return seen.get(goal, -1)

