var minSplitMerge = function(nums1, nums2) {
    const start = nums1.join(',');
    const goal = nums2.join(',');
    const n = nums1.length;
    const seen = new Map();
    seen.set(start, 0);
    const queue = [nums1.slice()];
    let head = 0;
    while (head < queue.length) {
        const arr = queue[head++];
        const key = arr.join(',');
        const d = seen.get(key);
        if (key === goal) return d;
        for (let L = 0; L < n; L++) {
            for (let R = L; R < n; R++) {
                const block = arr.slice(L, R + 1);
                const rest = arr.slice(0, L).concat(arr.slice(R + 1));
                for (let pos = 0; pos <= rest.length; pos++) {
                    const nxt = rest.slice(0, pos).concat(block, rest.slice(pos));
                    const nk = nxt.join(',');
                    if (!seen.has(nk)) {
                        seen.set(nk, d + 1);
                        queue.push(nxt);
                    }
                }
            }
        }
    }
    return seen.has(goal) ? seen.get(goal) : -1;
};
